var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"18시간 후. 북방합의체 영토권. 시베리아 중부, 봉쇄 균열.","JPN":"18時間後。北方合意体領土圏。シベリア中部、封鎖亀裂。","ENG":"Eighteen hours later. Northern Union Territory. Central Siberia, Sealed Crevice.","TWN":"18小時後，北方和議會領土圈，西伯利亞中部、封鎖大峽谷。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 지정 코드명- <color=#ffd34c>그라운드 제로</color>","JPN":"管理局指定コードネーム - <color=#ffd34c>グラウンド・ゼロ</color>","ENG":"Administration-appointed Codename- <color=#ffd34c>Ground Zero</color>","TWN":"管理局指定代號 - <color=#ffd34c>Ground Zero</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"중장님. 보고드립니다.","JPN":"中将、報告します。","ENG":"Lieutenant General, reporting in.","TWN":"中將，報告。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L7_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"현재 위치하신 C2 섹터에서 D5섹터까지, 북방합의체의 특이동향은 발견되지 않았습니다.","JPN":"現在いらっしゃるC2セクターよりD5セクターまで、北方合意体の特筆すべき動向は観測されていません。","ENG":"From our current position in Sector C2 to Sector D5, no unusual Northern Union activity detected.","TWN":"從您目前所在的C2區域到D5區域，尚未發現北方和議會的異常動向。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 최근 침입자가 발생했다는 이유로 경비가 삼엄할 줄 알았는데 예상외로 순탄하군.","JPN":"ああ。最近あったという侵入者発生の影響で警備が厳しくなっていると予想したが、案外順調だな。","ENG":"I see. I expected tighter security after the recent intrusions, but things are smoother than expected.","TWN":"好，還以為警備會因為最近有人入侵變得森嚴，結果卻意外順利。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"덕분에 불필요한 충돌은 피할 수 있겠어.","JPN":"おかげで、不要な衝突は避けられそうだ。","ENG":"All the better to avoid unnecessary clashes.","TWN":"多虧如此，應該能省去不必要的出動。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그렇지만… 정말 괜찮을까요?","JPN":"ですが……本当に大丈夫でしょうか？","ENG":"Still... Are we really fine with this?","TWN":"但是…真的沒問題嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"저는 군사학이나 집단간의 복잡한 이해관계에 관해 중장님만큼 해박하지 않습니다.","JPN":"私は軍事学や、集団同士の複雑な利害関係について中将ほど詳しくありません。","ENG":"I'm not as versed in military science or complex intergroup interests as you are.","TWN":"無論是軍事學或群體間複雜的利害關係，我都沒有中將這麼淵博。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"하지만 양측 지휘관끼리 독대하고 싶다는 합의체의 요구는 비정상적이라고 생각해요.","JPN":"ですが、指揮官同士で会談の場を持ちたいという合意体の要求は異常だと思います。","ENG":"But the Northern Union insisting on a one-on-one between commanders feels abnormal.","TWN":"但我認為和議會要求雙方指揮官單獨會面是不正常的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"합중국의 특수전사령부가 움직였으니 경계심이 올라가는 건 당연하지.","JPN":"合衆国の特殊戦司令部が動いたんだ。警戒を強めるのは当然のことだ。","ENG":"The States Strategic Special Operations Command is mobilizing. Of course their guard is up.","TWN":"既然合眾國特種作戰司令部已經採取行動，當然就要提高警戒。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"우릴 상대로 전쟁이라도 벌일 심산이 아닌 이상, 자네 걱정처럼 되지는 않을 거야.","JPN":"我々を相手に戦争を起こすつもりでもない限り、君の心配してるようなことにはならないだろう。","ENG":"Unless they plan to wage war on us, your worst-case will not come to pass.","TWN":"除非是想和我們開戰，否則事情應該不會演變成妳擔心的那樣。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"무엇보다 싸울 <color=#ffd34c>준비</color>라면 이미 끝마치지 않았나?","JPN":"何より、戦う<color=#ffd34c>準備</color>ならもう済ませているじゃないか。","ENG":"Above all, our <color=#ffd34c>preparations</color> to fight are complete, are they not?","TWN":"最重要的是，我們不是已經做好戰鬥的<color=#ffd34c>準備</color>了嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……죄송해요. 중장님을 믿지 못한다는 소리는 아니었어요.","JPN":"……申し訳ありません。中将のことを信用できないという意味ではありませんでした。","ENG":"...My apologies. I didn't mean I don't trust you.","TWN":"……抱歉，我的意思不是信不過中將。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"천만에. 나도 자네가 있으니 이런 대담한 짓을 벌일 수 있는 걸세.","JPN":"いや。私にこんな大胆な真似ができるのは、君がいてくれるおかげだ。","ENG":"Think nothing of it. With you here, I can afford to be this bold.","TWN":"別這麼說，我也是因為有妳在，才能做出這種大膽的事。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"신원 확인. 마리아 안토노프 중장의 출입을 허락합니다.","JPN":"身元確認。マリア・アントノフ中将の入室を許可します。","ENG":"Identity confirmed. Lieutenant General Maria Antonov is cleared to enter.","TWN":"身分確認，允許瑪麗亞·安東諾夫中將進入。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L25_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"각하께서 계신 방으로 모시겠습니다, 이쪽으로.","JPN":"閣下の部屋までご案内します。こちらへ。","ENG":"I will escort you to the General's room. This way.","TWN":"我帶您到閣下的房間，請往這邊走。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그럼…….","JPN":"では……","ENG":"Then...","TWN":"那麼……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"다시 연락하지, 제이나.","JPN":"また連絡する、ジェイナ。","ENG":"I'll be in touch, Jaina.","TWN":"再聯絡吧，婕娜。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"메모리 아카이브 동기화–– 데이터 정렬 완료.","JPN":"メモリーアーカイブ同期化──データ整列完了。","ENG":"Memory archive synchronization–– Data alignment complete.","TWN":"記憶體存檔同步––資料排序完畢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"사용자의 기억 체계에 따른 가상현실 구축 프로토콜 실행합니다.","JPN":"使用者の記憶体系による仮想現実構築プロトコルを実行します。","ENG":"Initializing VR construction protocol based on the user's memory schema.","TWN":"根據使用者的記憶系統執行虛擬現實構建協議。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"반복 횟수–––– ■■■■■번.","JPN":"反復回数────■■■■■回。","ENG":"Iteration count–––– ■■■■■ times.","TWN":"反覆次數–––– ■■■■■次。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_TECH_03"},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"여기는 시렌 추격전대…! 단방향 송신기를 통해 본부로 긴급 상황을 전파합니다!","JPN":"こちら、シレン追撃戦隊……！　単方向の送信機を通じて本部に緊急状況をお伝えします！","ENG":"This is the Sirin Tracking Division...! Sending an emergency message to HQ through a one-way transmitter!","TWN":"這裡是賽蓮追擊戰隊…！透過單向發送器向本部發送緊急情況！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"사도의 전력이 예상한 것보다 압도적으로 강합니다…!","JPN":"使徒の戦力が予想よりも圧倒的に強いです……！","ENG":"The Apostle's power is overwhelmingly more powerful than we expected...!","TWN":"使徒的戰力比預期還要強太多了…！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"우리 전대는 궤멸에 가까운 타격을 입었고…! 생존한 대원들은 시간을 벌 수 있도록 산개했습니다!","JPN":"こちらの戦隊は壊滅に近いダメージを受け……！　生き残った隊員たちは時間を稼げるように散開中であります！","ENG":"Our division has suffered a critical blow that was close to annihilation...! The surviving members have been ordered to scatter to buy more time!","TWN":"我們的戰隊遭受了近乎毀滅的打擊…！倖存隊員則是分散開來爭取時間！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"승산은 없습니다! 격리된 사도는 예정보다 빨리 풀려날 겁니다!","JPN":"勝ち目はありません！　隔離された使徒は予定より早く解放されるでしょう！","ENG":"There is no hope! The isolated Apostle will be released sooner than expected!","TWN":"毫無勝算！被隔離的使徒會比預期更快被釋放！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"펜릴이 마왕을 서둘러 처치하지 않으면…!","JPN":"早くフェンリルが魔王を始末しないと……！","ENG":"If the Fenrir doesn't defeat the Demon Lord soon...!","TWN":"要是芬里爾不盡快消滅魔王的話…！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"크윽…!","JPN":"ううっ……！","ENG":"Kgh...!","TWN":"咳呃…！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"숨을 수 있을 줄 알았어?","JPN":"隠れられるとでも思ったのか？","ENG":"Did you really think you could hide from me?","TWN":"妳以為自己躲得了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"그렇게 피를 흘리고 있으면, 냄새로 찾아낼 수밖에 없잖아. 사냥감.","JPN":"それだけ血を流してたら、匂いで探せるんだ。獲物。","ENG":"I can smell you right away when you're bleeding that much, prey.","TWN":"要是那樣流血的話，就只能憑藉味道找出來了，獵物。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"날… 먼저 쫓아온 건가?","JPN":"私を……先に狙って来たのか？","ENG":"Did you... come after me first?","TWN":"難道…你ˋ是先追著我來嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"아니? 다른 녀석들은 진작에 처리했는데?","JPN":"いや？　他の奴らはすでに始末した。","ENG":"No. I already took care of the others a long time ago.","TWN":"不，我早就把其他傢伙消滅了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"네가 마지막이야.","JPN":"あんたが最後だな。","ENG":"You're the last one.","TWN":"妳是ˋ最後一個。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"안돼… 이렇게 빨리 전멸하면 본대가…!","JPN":"駄目だ……こんなに早く全滅したら本隊が……！","ENG":"No... If we are wiped out this fast, the main forces will–!","TWN":"不行…要是這麼快就全軍覆沒，本隊…！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"아, 그건 걱정 마. 난 처음부터 너희랑 놀아주러 온 거니까.","JPN":"あ、それなら心配するな。アタシは最初からあんたたちと遊ぶために来たんだからな。","ENG":"Oh, don't you worry about that. I came here to play with you from the start.","TWN":"啊，這點妳不用擔心，我一開始就是來陪你們玩的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"…뭐?","JPN":"……何？","ENG":"...What?","TWN":"…什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"우리 마왕님은 <color=#ffd34c>진짜</color> 싸움을 즐길 때 방해받는 걸 싫어하시거든.","JPN":"うちの主様は<color=#ffd34c>本物</color>の戦いを楽しむ時に邪魔されるのが嫌いなんだ。","ENG":"Our Demon Lord hates being bothered when she's enjoying a <color=#ffd34c>real</color> fight.","TWN":"我們魔王享受<color=#ffd34c>真正</color>戰鬥的時候討厭被人打擾。 "},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"다른 조무래기가 끼어들면 흥이 깨지니 말이야.","JPN":"他の雑魚が割り込むと興が冷めるからな。","ENG":"And her excitement will be ruined if grunts like you butt in.","TWN":"要是其他小毛頭攪和的話會很掃興。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"사도 없이도… 마왕이 승리를 확신하고 있다고?","JPN":"使徒なしでも……魔王が勝利を確信しているだと？","ENG":"Even without her Apostles... the Demon Lord is certain of her victory?","TWN":"沒有使徒…也確信是魔王勝利？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"하핫, 당연하잖아. 사도에게 의지하는 나약한 것들과 우리 주인님은 다르거든.","JPN":"ははっ、当たり前だろう。主様は使徒に頼る弱いものどもとは違う。","ENG":"Haha! Of course! My mistress is different from those weaklings that rely on their Apostles.","TWN":"哈哈，這是當然了，那些依賴使徒的弱者和我們主人不一樣。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"자, 넌 무슨 능력으로 날 재밌게 해줄 거지? 어서 보여줘.","JPN":"さあ、あんたはどんな能力でアタシを楽しませてくれるんだ？　早く見せてくれ。","ENG":"Now, with what ability will you entertain me? Let's see it.","TWN":"好，妳要用什麼能力取悅我？快讓我看看。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"응? 너 설마 능력이 없는 거냐?","JPN":"あ？　あんた、まさか能力がないのか？","ENG":"Hmm? You don't have any ability?","TWN":"嗯？難道妳沒有能力嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"이거 김 빠지네. 부하 녀석들도 시원찮던데. 뭘 믿고 너희 같은 녀석들에게 날 맡긴 거지?","JPN":"興覚めだな。部下のやつらも大したことなかったのに。何を思ってあんたたちみたいなやつらにアタシを任せたんだ？","ENG":"This is a let-down. Even your subordinates were too weak. What makes them think you can stand against me?","TWN":"這真是令人失望，我看部下們也不怎麼樣，憑什麼把我交給你們這些傢伙？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"아니면 관리국이 우릴 잡으려고 강한 놈을 아껴둔 게 아니라, 너 같은 잔챙이들을 이용해서라도 시간을 벌어야 할 만큼 절박했단 건가?","JPN":"それか管理局がアタシたちを捕まえるために強いやつらをキープしておいたんじゃなくて、あんたみたいな雑魚を利用してでも時間を稼がなきゃいけないほど追い込まれていたとか？","ENG":"Or is it that the Administration wasn't hiding their strong ones to face us, but was trying to buy time by using chumps like you?","TWN":"還是管理局不是為了抓我們先保留強者，而是迫切地要利用你這種小人物來爭取時間？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"관리국은 지지 않아.","JPN":"管理局は負けない。","ENG":"The Administration will not lose.","TWN":"管理局不會輸。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"모두가 함께 맹세했다. 마왕을 이기고… 세상을 구해낼 거라고.","JPN":"皆で一緒に誓ったんだ。魔王に勝ち……世界を救うと。","ENG":"We all made an oath. That we'll defeat the Demon Lord... and save the world.","TWN":"我們所有人一起發過誓，要贏過魔王…拯救世界。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"하핫! 그래, 자기가 따르는 무리를 믿는 게 나쁜 건 아니지.","JPN":"ははっ！　そうさ、自分が従っている群れを信じるのは悪いことじゃない。","ENG":"Haha! Yeah, it's not a bad thing to trust your people.","TWN":"哈哈！好，相信自己跟隨的群體不是件壞事。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"네 우두머리는 널 미끼 정도로 생각하는 것 같지만 말이야.","JPN":"あんたのリーダーは、あんたをエサ程度にしか思ってないみたいだけどな。","ENG":"But I think your leader thinks of you as nothing but bait.","TWN":"雖然妳的首領應該是把妳當成誘餌。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SCAENA_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"여기는 본부… 본 무전은 클리파 차원 내의 관리국 인원들에게 전파하는 단방향 발신이다.","JPN":"こちら、本部……この無線はクリファ次元内の管理局全員に伝える単方向発信だ。","ENG":"This is HQ... This radio is a one-way transmission to all Administration personnel within the Qlipha Dimension.","TWN":"這裡是本部…此無線電訊息是傳播給逆卡巴拉次元內管理局人員的單向發送。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"늑대의 사망을 확인했다. 목표 달성은 실패다.","JPN":"オオカミの死亡を確認した。目標の達成は失敗だ。","ENG":"The Wolf is confirmed dead. We have failed to achieve our goal.","TWN":"確認狼已死亡，未能達成目標。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"남은 생존자는 신속하게 클리파 차원에서 철수하라.","JPN":"残りの生存者は速やかにクリファ次元から撤退しろ。","ENG":"All remaining survivors must quickly withdraw from the Qlipha Dimension.","TWN":"倖存者要迅速撤離逆卡巴拉次元。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"반복한다. 대피가 가능한 관리국 대원은 즉시 클리파 차원에서 철수…","JPN":"繰り返す。退避可能な管理局隊員は直ちにクリファ次元から撤退……","ENG":"I repeat. All Administration personnel who are able should immediately evacuate from the Qlipha Dimension...","TWN":"再說一次，可疏散的管理局隊員立即撤離逆卡巴拉次元…"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"늑대가… 죽었다고?","JPN":"オオカミが……死んだと？","ENG":"The Wolf... is dead?","TWN":"狼…死了？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"그렇게 됐다는군.","JPN":"そうみたいだな。","ENG":"So it seems.","TWN":"聽說是這樣。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"결투에서 진 녀석들이 도망친다고 무슨 소용인진 모르겠지만…","JPN":"決闘で負けたやつらが逃げても何の役にも立たないと思うが……","ENG":"I don't know what use it is for losers to flee from battle, but...","TWN":"雖然不知道那些在戰鬥中落敗的傢伙逃跑有什麼用…"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"아- 여기에 갇힌 넌 그 마저도 할 수도 없겠네.","JPN":"ああー、ここに閉じ込められたあんたはそれさえもできないんだな。","ENG":"Oh, right. You're trapped here, so you can't even do that.","TWN":"啊，妳被關在這裡應該連那個也做不到。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"안 그래?","JPN":"そうだろう？","ENG":"Isn't that right?","TWN":"妳說是不是？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"시렌 전대는…","JPN":"シレン戦隊は……","ENG":"As the Sirin Division...","TWN":"賽蓮戰隊…"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"…물러서지 않고 끝까지… 적을 추적한다.","JPN":"……引き下がらず、最後まで……敵を追跡する。","ENG":"...We do not retreat... and track the enemy to the end.","TWN":"…不會退縮，而是會…追擊敵人直到最後。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"크하핫, 궁지에 몰린 먹잇감이 아직도 꼬리를 세우다니. 용기는 인정해야겠어.","JPN":"フハハッ、窮地に追い込まれた獲物がまだ威嚇してくるとはな。その勇気は認めてやる。","ENG":"Kah ha ha! A cornered prey still trying to fight. I admire your courage.","TWN":"哈哈哈，陷入困境的獵物竟然還翹起尾巴，應該認可妳的勇氣。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"좋지! 덤비라고…!","JPN":"いいぞ！　かかって来い……！","ENG":"All right! Let's see what you've got...!","TWN":"很好！給我放馬過來…！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_05"},{"id":"L45_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"크윽…!!","JPN":"くっ……！！","ENG":"Kgh...!!","TWN":"咳呃…！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"뭐해? 명색이 전대장이라면 엎드리지 말고 일어나 싸우라고.","JPN":"何してんだ？　戦隊長なら戦隊長らしく、立ち上がって戦え。","ENG":"What are you doing? If you're a commander, don't grovel. Get up and fight.","TWN":"幹什麼？既然是戰隊長，就不要趴著，給我起來戰鬥。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"맥없이 가버린 네 부하들 몫만큼은 싸워야 내 성이 찰 것 아냐?","JPN":"あっけなくくたばっちまったあんたの部下の分まで戦ってくれないと、アタシは満足できないんだ。","ENG":"At least fight for the share of your pitiful subordinates who dropped so easily.","TWN":"妳的部下無精打采地離開了，要連他們的份一起戰鬥我才會滿足，不是嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"대체… 뭐가 즐거워서 그렇게 웃는 거지?","JPN":"何が……何が楽しくて笑っていられる？","ENG":"What's so funny... that you keep laughing?","TWN":"你到底…在開心什麼，笑成這樣？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"너흰 사람의 목숨을 뭐라고 생각하는 거야…!","JPN":"お前たちは人の命を何だと思ってるんだ……！","ENG":"What do you think human life is...?!","TWN":"你們把人命當成什麼…！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"하? 내가 왜 그런 걸 신경 써야 하는데?","JPN":"は？　そんなもん気にするわけないだろ。","ENG":"Huh? Why should I care?","TWN":"哈？我為什麼要在意那種事？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"억울하면 네가 나보다 강하면 그만이잖아?","JPN":"悔しいならアタシより強くなればいいじゃないか。","ENG":"If you're bitter, just be stronger than me.","TWN":"委屈的話，妳比我強不就好了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"기억해 둬. 싸움에 필요한 건 남을 쫓는 다리가 아닌, 사냥감을 물어뜯는 이빨이야.","JPN":"覚えておきな。戦いに必要なのは人を追いかける脚じゃない、獲物を噛みちぎる牙だ。","ENG":"Remember this. What you need for battle is not legs to chase others, but teeth to tear into prey.","TWN":"記住，戰鬥需要的不是追逐別人的腿，而是啃咬獵物的牙齒。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"잔챙이들이 남의 뒤꽁무니나 쫓았으니 마지막이 개죽음인 거라고.","JPN":"雑魚のくせに後なんか追ってくるから最期に犬死するんだ。","ENG":"Tag-along runts die like dogs at the end.","TWN":"小嘍囉跟在別人屁股後面，最後就是白白送死。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"너 같은 괴물이 내 동료들을 모욕하지 마!","JPN":"化け物が私の仲間を侮辱するな！","ENG":"Don't you dare insult my comrades, monster!","TWN":"像你這樣的怪物不要侮辱我的同伴！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L7_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"분명 펜릴이… 관리자님이, 아직…!!","JPN":"きっとフェンリルが……管理者様が、まだ……！！","ENG":"I am sure Fenrir... the Administrator is still...!!","TWN":"肯定是芬里爾…管理者，還沒…！！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"반복한다. 늑대의 사망을 확인했다.","JPN":"繰り返す。オオカミの死亡を確認した。","ENG":"I repeat. The Wolf is confirmed dead.","TWN":"再說一次，確認狼已死亡。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"생존자는 클리파 차원에서… 신속하게 철수……","JPN":"残りの生存者は速やかにクリファ次元から……直ちに撤退……","ENG":"All remaining survivors must quickly withdraw... from the Qlipha Dimension...","TWN":"倖存者要迅速撤離…逆卡巴拉次元……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"……지지 않았어.","JPN":"……負けてない。","ENG":"...We haven't lost.","TWN":"……沒有輸。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"아직, 우리는…….","JPN":"まだ、私たちは……","ENG":"Not yet, we...","TWN":"我們還沒輸……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"쳇. 용기 있는 녀석인 줄 알았는데 결국 이정도인가?","JPN":"ちっ。度胸のあるやつだと思ったが、所詮この程度か？","ENG":"Tch. I thought you had guts, but this is all that you've got?","TWN":"嘖，我還以為妳很有勇氣，結果只有這點程度？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"전대장이라서 기억할만한 녀석인가 싶었는데, 이래서야 망가진 장난감이잖아.","JPN":"戦隊長っていうから記憶しとく価値のあるやつなのかと思ったら、これじゃただの壊れたオモチャじゃないか。","ENG":"A commander worth remembering, or so I thought. You just look like a broken toy.","TWN":"因為是戰隊長，我心想妳會是個值得記住的人，結果不就是個壞掉的玩具嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"알려주세요, 관리자님.","JPN":"教えてください、管理者様。","ENG":"Please tell me, Administrator.","TWN":"告訴我吧，管理者。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"narration","speaker":null,"text":{"KOREA":"관리국의 동료들… 시렌 전대 전우들의 희생이.","JPN":"管理局の同僚たち……シレン戦隊の戦友の犠牲は。","ENG":"The sacrifices of our comrades in the Administration... of the Sirin Division.","TWN":"管理局的同伴…賽蓮戰隊戰友們的犧牲，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>이 세계</color>를 지키기 위해 도움이 되었을까요?","JPN":"<color=#ffd34c>この世界</color>を守るために、役立ちましたか？","ENG":"Did they help protect <color=#ffd34c>this world</color>?","TWN":"會對守護<color=#ffd34c>這世界</color>有幫助嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"마왕 측 전력이 예상을 상회… 대부분의 전대가 궤멸했다…….","JPN":"魔王側の戦力が予想を上回り……ほとんどの戦隊が壊滅した……","ENG":"The Demon Lord's forces exceeded expectations... most divisions were annihilated...","TWN":"魔王那邊的戰力超乎預期…大部分的戰隊都毀滅了……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이번</color> 클리포트 게임은…… 우리의 패배다.","JPN":"<color=#ffd34c>今回の</color>クリフォトゲームは……我々の負けだ。","ENG":"<color=#ffd34c>This</color> Qliphoth Game... is our defeat.","TWN":"<color=#ffd34c>這次</color>逆卡巴拉遊戲……我們落敗了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"이제 저항할 생각도 없나 보네.","JPN":"もう抵抗する気もないみたいだな。","ENG":"So you've given up struggling.","TWN":"看來現在也不想反抗了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"그만 죽어.","JPN":"死ね。","ENG":"Then die.","TWN":"就去死吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"…이상 침입 감지.","JPN":"……異常侵入を感知。","ENG":"...Detecting an abnormal intrusion.","TWN":"…偵測到異常入侵。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"인과율 모순 발생에 따라, 프로토콜을 강제 종료합니다.","JPN":"因果律に矛盾が発生。プロトコルを強制終了します。","ENG":"In accordance to causality contradiction occurring, forcing protocol shutdown.","TWN":"根據因果關係矛盾發生，強制終止協議。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"곧 손님이 올 시간입니다.","JPN":"まもなくお客様が到着する時間です。","ENG":"Our guest will arrive shortly.","TWN":"馬上就到客人要來的時候了。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"마침 목을 축일 차도 준비되었으니, 오늘은 이만하시죠.","JPN":"喉を潤すお茶も用意しましたので、今日はこの辺にしておきましょう。","ENG":"Tea is ready to quench our thirsts, so let us stop for today.","TWN":"我正好準備了能潤喉的茶，今天就到此為止吧。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"응. 그래야겠네.","JPN":"ああ、そうだな。","ENG":"Yes. Let us.","TWN":"嗯，應該這樣才對。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"아무래도 조금 몰두한 모양이야.","JPN":"少し没頭しすぎたようだ。","ENG":"I seem to have gotten a bit absorbed.","TWN":"看來好像有點專注了。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"기억 속 죽음을 반복하는 행위를 말입니까?","JPN":"記憶の中の死を繰り返す行為にですか？","ENG":"You mean reliving your deaths in memory?","TWN":"妳指的是記憶中反覆死亡的行為嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"부정적인 감정은 대개 인간의 원동력이 돼.","JPN":"ネガティブな感情は人間の原動力になる。","ENG":"Negative feelings often become a human's driving force.","TWN":"負面情緒通常會成為人的原動力。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"지금 지닌 감정이 당시 느꼈던 바에 비하지는 못할 테니…….","JPN":"どれほど切実な感情と言えど、歳月と共に擦り減ってしまう。だから……","ENG":"What I feel now cannot match what I felt then, of course...","TWN":"現在擁有的情感無法與當時感受到的相比……"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"나름대로 좋은 자극이 되겠지.","JPN":"それなりにいい刺激になってくれるだろう。","ENG":"But it serves as decent stimulation.","TWN":"應該會是種不錯的刺激吧。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"의외군요. 그런 감정에는 이미 무뎌진 줄 알았습니다.","JPN":"意外ですね。そういった感覚はすでに麻痺していると思っていました。","ENG":"Surprising. I thought you were numb to such emotions.","TWN":"真意外，還以為妳已經對那種情感麻木了。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"글쎄. 확신할 수 없는 미래는 누구에게나 큰 불안요소가 아닐까?","JPN":"どうかな。確信できない未来は誰にとっても大きな不安要素ではないか？","ENG":"Who knows. An uncertain future is a major source of anxiety for anyone.","TWN":"這個嘛，無法確信的未來對任何人來說都是極大的不安因素吧？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"당신도 그걸 알기에, 지금 내 앞에 모습을 드러낸 거겠지.","JPN":"君もそれを分かっているからこそ、今私の前に姿を現したのだろう。","ENG":"You know that too, which is why you are showing yourself to me now.","TWN":"妳也是知道這點，現在才會在我面前出現吧。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"……삼하인.","JPN":"……サウィン。","ENG":"...Samhain.","TWN":"……薩溫。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"섭섭한 말을 하는군요. 난 어디에나 있고, 어디서든 당신을 지켜보고 있습니다.","JPN":"寂しいことを言いますね。私はどこにでも存在し、どこからでもあなたを見守っています。","ENG":"How cold. I am everywhere, watching you from anywhere.","TWN":"妳說的話真令人難過，我無所不在，無論在哪都在盯著妳。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"이를 테면 당신이 전대장인 세계로부터 이어진 운명의 끈.","JPN":"例えば、あなたが戦隊長であった世界から繋がってきた運命の糸。","ENG":"For example, the thread of fate that led here from the world where you were a division commander.","TWN":"比如說，從妳身為戰隊長的世界延續下來的命運之繩。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"시렌 전대의 말더듬이 신병… 그래요, 분명 나탈리아라는 이름이었죠.","JPN":"シレン戦隊のどもりが酷かった新兵……そう、確かナタリアという名前でしたね。","ENG":"Sirin Division's stammering recruit... Yes, her name was Natalia.","TWN":"賽蓮戰隊的口吃新兵…是啊，名字明明叫那塔利亞。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"현 시간선에서도 그 아이를 찾아 보호한 걸 보면 제법 소중한 존재였나 보군요.","JPN":"あなたは今の時間線でもその子を見つけ出して保護した。随分大切な存在だったようですが？","ENG":"Seeing as you sought her out and protected her in this timeline as well, she must be dear to you.","TWN":"看妳在目前的時間線上找到並保護那個孩子，她應該是十分珍貴的存在。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그 아인 합의체와 적대관계에 있는 자들을 끌어들이기 위한 장치에 불과해.","JPN":"あの子は合意体と敵対関係にある者たちを引き入れるための装置にすぎない。","ENG":"She is merely a tool to draw in those who stand against the Northern Union.","TWN":"那個孩子只不過是為了拉攏與和議會是敵對關係之人而生的裝置。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"손을 더럽히지 않은 중개역은 북방합의체에도 필요한 법이거든.","JPN":"手を汚していない仲介役が、北方合意体にも必要なのでな。","ENG":"Even we need a go-between who doesn't have blood on their hands.","TWN":"北方和議會也需要沒把手弄髒的中繼站。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"글쎄요. 어쩌면 거두지 못한 인간성의 편린이 당신을 옭아매고 있을지도 모르죠.","JPN":"そうでしょうか……もしかすると、あなたは捨てきれなかった人間性の片鱗に縛られているのかもしれませんよ。","ENG":"Who knows? Perhaps scraps of the humanity you failed to discard still bind you.","TWN":"這個嘛，也許沒能收起的人性片段正束縛著你。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"내가 아는 당신은 소중한 걸 곁에 두지 않는 사람이니까요.","JPN":"私が知る限りでは、あなたは大切なものをそばに置いたりしない人ですから。","ENG":"The you I know does not keep what is precious close.","TWN":"因為我所認識的妳是不會把珍貴的東西放在身邊的人。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"……내게 경각심이라도 줄 셈이려나?","JPN":"……戒めのつもりか？","ENG":"...Trying to warn me, are you?","TWN":"……妳是打算讓我有所警惕嗎？"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"나는 그저 미약하게 남은 당신의 인간성이 현실에 영향을 미칠지 궁금했을 뿐입니다.","JPN":"私はただ、微かに残ったあなたの人間性が、現実に影響を及ぼさないか気になっただけです。","ENG":"I am simply curious whether that faint remnant of humanity will influence reality.","TWN":"我只是好奇妳所剩不多的人性會不會對現實造成影響。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"선로의 끝에 다다르기 위해, 인간이 극복해야 할 시련은 너무나도 방대하니까요.","JPN":"線路の果てにたどり着くために、人間が乗り越えるべき試練はあまりにも膨大ですから。","ENG":"The trials humanity must overcome to reach the end of the tracks are vast.","TWN":"為了到達軌道的盡頭，人類必須克服的考驗實在太龐大了。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"걱정 마. 당신이 준 정보를 토대로 합의체가 할 수 있는 준비는 끝마쳤어.","JPN":"案ずるな。君にもらった情報をもとに、合意体にできる準備はすべて済ませてある。","ENG":"Not to worry. Based on the intel you provided, the Northern Union's preparations are complete.","TWN":"別擔心，我已經以妳給的情報為基礎做好和議會能做的準備了。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"신성에 저항하는 무녀와 동일한 능력의 클론을 양산하는 <color=#ffd34c>프로젝트 오라클.</color>","JPN":"神聖に抵抗する巫女と同じ能力を持つクローンを量産する、<color=#ffd34c>プロジェクト・オラクル</color>。","ENG":"<color=#ffd34c>Project Oracle</color>, mass-producing clones with the same ability as the priestess who resists Divinity.","TWN":"量產與抵抗神聖的巫女具有相同能力的複製人的<color=#ffd34c>甲骨文計畫。</color>"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"기억에서 파생된 감정을 동력원으로 삼는 코어의 제작.","JPN":"記憶から派生した感情を動力源とするコアの製作。","ENG":"Building cores that run on emotions derived from memory.","TWN":"製作以從記憶衍生的情感做為動力來源的核心。"},"stage":{"bg":"MAVKA_02","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그리고 이를 통한 전략병기를 운용하는 <color=#ffd34c>프로젝트 마트료시카.</color>","JPN":"そしてそれを活用した戦略兵器を運用する、<color=#ffd34c>プロジェクト・マトリョシカ</color>。","ENG":"<color=#ffd34c>Project Matryoshka</color>, a strategic weapons program powered by those cores.","TWN":"然後是藉此運用戰略兵器的<color=#ffd34c>俄羅斯娃娃計畫。</color>"},"stage":{"bg":"MAVKA_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"마지막으로 그림자를 통제하는 <color=#ffd34c>프로젝트 셰퍼드</color>까지.","JPN":"最後に、シャドウをコントロールする<color=#ffd34c>プロジェクト・シェパード</color>まで。","ENG":"And lastly, <color=#ffd34c>Project Shepherd</color> to control the Shadows.","TWN":"最後還有控制暗影的<color=#ffd34c>牧羊人計畫</color>。"},"stage":{"bg":"FLOOR_03","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"아직 불완전하지만, 각 프로젝트의 적성 개체들을 토대로 유의미한 결과가 나타났어.","JPN":"まだ不完全ではあるが、各プロジェクトの適性個体から有意義な結果が得られた。","ENG":"Incomplete as they are, each project has yielded meaningful results with compatible subjects.","TWN":"雖然還不完整，但根據每個計畫的適應性個體，出現了有意義的結果。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"암군의 영향력이 현실을 장악한들, 계획에 차질은 없겠지.","JPN":"暗君の影響力が現実を掌握しても、計画に支障が出ることはないだろう。","ENG":"Even if the Ignorant Monarch's influence grips reality, the plan will hold.","TWN":"就算昏君的影響力掌控現實，計畫也不會有差錯吧。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"글쎄요. 당신이라면 잘 알고 있지 않습니까?","JPN":"そうでしょうか。あなたはよくご存じのはずです。","ENG":"Will it? You of all people know this.","TWN":"這個嘛，妳應該很清楚吧？"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"이 세계를 핍박하는 시련은 결코 한 존재로부터 야기된다는 것이 아니란 걸요.","JPN":"この世界を脅かす試練、それを科す存在は決して1つにとどまらないということを。","ENG":"The trials pressing this world are never born of a single being.","TWN":"逼迫這個世界的考驗，絕對不是從一個存在引發的。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"응. 잘 알고 있어.","JPN":"ああ、よく知っている。","ENG":"Yes, I know.","TWN":"嗯，我很清楚。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"후후. 내가 불필요한 말을 했나 보군요.","JPN":"ふふ、つい要らないことを口走ってしまいましたね。","ENG":"Haha. Then I have said too much.","TWN":"呵呵，看來我說了沒必要的話。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"계약의 청약자이자 당신의 운명에 오른 승객으로서, 나는 다시 그늘의 밑바닥으로 돌아가겠습니다.","JPN":"契約の申出人でありあなたの運命に乗った乗客として、私は再び陰の底に帰りましょう。","ENG":"As the offeror of the contract, and a passenger riding your fate, I shall return to the bottom of the shade.","TWN":"身為契約的要約人和登上妳命運的乘客，我要再次回到陰暗的低谷。"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"부디, 당신이 목표하는 바를 이룰 수 있기를…….","JPN":"どうか、あなたが目的を達成できますように……","ENG":"May you achieve what you seek...","TWN":"希望妳一定要達成目標……"},"stage":{"bg":"MIND","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_QM","text":{"KOREA":"이런, 설마 그쪽에서 기다리고 있을 줄은 몰랐군.","JPN":"おや、まさか待たせていたとは思わなかった。","ENG":"My, I didn't expect you to be waiting on that side.","TWN":"哎呀，我沒想到妳會在那裡等我。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_QM","text":{"KOREA":"기다리다가 차가 식은 건 아닌가 모르겠어.","JPN":"待っている間にお茶が冷めてしまっただろうか。","ENG":"I hope the tea did not go cold while you waited.","TWN":"不知道是不是等到後來茶涼了。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"아뇨. 뜨겁게 우려냈으니 마침 딱 좋은 정도일 거예요.","JPN":"いいえ、熱く淹れたのでちょうどいい温度になっているでしょう。","ENG":"Not at all. I brewed it hot, so it should be just right.","TWN":"不，剛才泡出來熱騰騰的，這樣應該正好。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"소문으로만 듣던 전쟁영웅을 뵙게 되어 영광입니다.","JPN":"噂で聞いていた戦争英雄にお会いできて光栄です。","ENG":"It is an honor to finally meet the war hero I had only heard of in rumors.","TWN":"能見到傳說中的戰爭英雄是我的榮幸。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"……마리아 안토노프 중장.","JPN":"……マリア・アントノフ中将。","ENG":"...Lieutenant General Maria Antonov.","TWN":"……瑪麗亞·安東諾夫中將。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"}]`);export{e as default};